ALGORITHM Calculate_Capacity(bandwidth, signal_power, noise_power)
BEGIN
 // Calculate Signal-to-Noise Ratio
 snr = signal_power / noise_power

 // Convert SNR to dB
 snr_db = 10 * log10(snr)

 // Shannon Capacity: C = B * log2(1 + S/N)
 capacity = bandwidth * log2(1 + snr)

 OUTPUT "SNR: " + snr + " (" + snr_db + " dB)"
 OUTPUT "Maximum Capacity: " + capacity + " bps"

 RETURN capacity
END

// Example: B = 3000 Hz, S/N = 1000 (30 dB)
// C = 3000 * log2(1001) ≈ 3000 * 9.97 ≈ 29.9 kbps

ALGORITHM Calculate_Nyquist(bandwidth, signal_levels)
BEGIN
 // Nyquist Formula: Max data rate = 2B * log2(M)
 // where M = number of signal levels

 max_data_rate = 2 * bandwidth * log2(signal_levels)

 OUTPUT "Bandwidth: " + bandwidth + " Hz"
 OUTPUT "Signal Levels (M): " + signal_levels
 OUTPUT "Maximum Data Rate: " + max_data_rate + " bps"

 RETURN max_data_rate
END

// Example: B = 3000 Hz, M = 4
// Max rate = 2 * 3000 * log2(4) = 6000 * 2 = 12 kbps
